import { expectDiagnostics } from "@typespec/compiler/testing";
import { describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";

// Shared entity fixture — proper Products.<X>.Entities.<Y> namespace
const ENTITY_FIXTURE = `
  namespace Products.MyProduct.Entities.Task {
    @entity
    model Task { id: string; }
  }
  using Products.MyProduct.Entities.Task;
`;

describe("@invariant", () => {
  describe("valid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T002.T002_01
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_invariant:Products.A10nBlueprintEngine.Features.DomainAuthoring.invariant_predicate_field:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_assumption:Products.A10nBlueprintEngine.Features.DomainAuthoring.invariant_predicate_field:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_invariant:Products.A10nBlueprintEngine.Features.DomainAuthoring.invariant_why_field:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_assumption:Products.A10nBlueprintEngine.Features.DomainAuthoring.invariant_why_field:must
    it("on an op inside a @feature namespace", async () => {
      // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_invariant
      const runner = await Tester.createInstance();
      await runner.compile(`
        ${ENTITY_FIXTURE}

        @feature
        namespace Products.MyProduct.Features.MyFeature {
          @invariant(#{
            predicate: "A {@Task} always has an id.",
            why: "The id is required for addressability.",
          })
          op task_has_id(): void;
        }
      `);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T002.T002_02
    it("predicate with inline refs validates correctly", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        ${ENTITY_FIXTURE}

        @feature
        namespace Products.MyProduct.Features.MyFeature {
          @invariant(#{
            predicate: "Every {@Task} has a non-empty {@Task.id}.",
            why: "Ensures uniqueness.",
          })
          op task_id_nonempty(): void;
        }
      `);
    });
  });

  describe("invalid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T002.T002_03
    it("op outside a @feature namespace", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        ${ENTITY_FIXTURE}

        @invariant(#{
          predicate: "A {@Task} always has an id.",
          why: "Addressability.",
        })
        op task_has_id(): void;
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-namespace-nesting",
        message: /invariant/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T002.T002_04
    it("predicate with unresolved inline ref", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @feature
        namespace Products.MyProduct.Features.MyFeature {
          @invariant(#{
            predicate: "A {@GhostEntity} must exist.",
            why: "Some reason.",
          })
          op ghost_exists(): void;
        }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/unresolved-inline-ref",
        message: /GhostEntity/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T002.T002_05
    it("why with unresolved inline ref", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        ${ENTITY_FIXTURE}

        @feature
        namespace Products.MyProduct.Features.MyFeature {
          @invariant(#{
            predicate: "A {@Task} has an id.",
            why: "Because {@GhostRef} says so.",
          })
          op task_has_id(): void;
        }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/unresolved-inline-ref",
        message: /GhostRef/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T002.T002_06
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_invariant:Products.A10nBlueprintEngine.Features.DomainAuthoring.inv_id_opname:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_assumption:Products.A10nBlueprintEngine.Features.DomainAuthoring.inv_id_opname:must
    it("op name with more than 3 words", async () => {
      // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_invariant
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        ${ENTITY_FIXTURE}

        @feature
        namespace Products.MyProduct.Features.MyFeature {
          @invariant(#{
            predicate: "A {@Task} has an id.",
            why: "Reason.",
          })
          op task_must_have_valid_id(): void;
        }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invariant-id-shape",
        message: /task_must_have_valid_id/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T002.T002_07
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_invariant:Products.A10nBlueprintEngine.Features.DomainAuthoring.inv_id_opname:should
    it("op name with numeric suffix", async () => {
      // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_invariant
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        ${ENTITY_FIXTURE}

        @feature
        namespace Products.MyProduct.Features.MyFeature {
          @invariant(#{
            predicate: "A {@Task} has an id.",
            why: "Reason.",
          })
          op task_has_001(): void;
        }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invariant-id-shape",
        message: /task_has_001/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T002.T002_08
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_invariant:Products.A10nBlueprintEngine.Features.DomainAuthoring.invariant_returns_void:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_assumption:Products.A10nBlueprintEngine.Features.DomainAuthoring.invariant_returns_void:must
    it("non-void return type", async () => {
      // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_invariant
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        ${ENTITY_FIXTURE}

        @feature
        namespace Products.MyProduct.Features.MyFeature {
          @invariant(#{
            predicate: "A {@Task} has an id.",
            why: "Reason.",
          })
          op task_has_id(): string;
        }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invariant-non-void-return",
        message: /task_has_id/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T002.T002_09
    it("duplicate @invariant on the same op", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        ${ENTITY_FIXTURE}

        @feature
        namespace Products.MyProduct.Features.MyFeature {
          @invariant(#{
            predicate: "A {@Task} has an id.",
            why: "Reason one.",
          })
          @invariant(#{
            predicate: "A {@Task} has an id again.",
            why: "Reason two.",
          })
          op task_has_id(): void;
        }
      `);
      expectDiagnostics(diagnostics, [
        { code: "@a10n/blueprint-typespec/duplicate-decorator", message: /invariant/ },
        { code: "@a10n/blueprint-typespec/duplicate-decorator", message: /invariant/ },
      ]);
    });
  });
});
